import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const s="/assets/clash-verge-rev-01.BFibmRaT.png",l="/assets/clash-verge-rev-02.DocnJoFD.png",n="/assets/clash-verge-rev-03.C-RlME5e.png",d="/assets/clash-verge-rev-04.Br33GEcG.png",h="/assets/clash-verge-rev-05.vFr3B6AX.png",f=JSON.parse('{"title":"Clash Verge Rev for Windows","description":"Windows 首选客户端 Clash Verge Rev 图文配置教程，五步完成订阅导入与连接。","frontmatter":{"description":"Windows 首选客户端 Clash Verge Rev 图文配置教程，五步完成订阅导入与连接。"},"headers":[],"relativePath":"clients/windows/clash-verge.md","filePath":"clients/windows/clash-verge.md","lastUpdated":1783294793000}'),i={name:"clients/windows/clash-verge.md"};function g(c,e,p,u,v,b){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="clash-verge-rev-for-windows" tabindex="-1">Clash Verge Rev for Windows <a class="header-anchor" href="#clash-verge-rev-for-windows" aria-label="Permalink to &quot;Clash Verge Rev for Windows&quot;">​</a></h1><blockquote><p><strong>现代化 GUI 客户端</strong> | 规则分流清晰、策略组管理强、上手直观</p></blockquote><p><a href="https://github.com/clash-verge-rev/clash-verge-rev" target="_blank" rel="noreferrer">Clash Verge Rev</a> 是基于 Clash 内核的图形客户端，适合需要规则分流、策略组切换和可视化操作的用户，也是自由港机场在 Windows 上的首选推荐。</p><h2 id="平台支持" tabindex="-1">平台支持 <a class="header-anchor" href="#平台支持" aria-label="Permalink to &quot;平台支持&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>Windows</td><td>完全支持</td><td>本文档适用平台</td></tr><tr><td>macOS</td><td>完全支持</td><td>另有 <a href="./../macos/clash-verge">macOS 教程</a></td></tr><tr><td>Linux</td><td>完全支持</td><td>桌面发行版可用，见 <a href="./../others/linux">Linux 教程</a></td></tr></tbody></table><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>最低要求</th><th>推荐配置</th></tr></thead><tbody><tr><td><strong>操作系统</strong></td><td>Windows 10</td><td>Windows 11</td></tr><tr><td><strong>架构</strong></td><td>x64</td><td>x64</td></tr><tr><td><strong>内存</strong></td><td>4GB</td><td>8GB 及以上</td></tr><tr><td><strong>存储空间</strong></td><td>300MB</td><td>1GB 及以上</td></tr></tbody></table><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ul><li>Windows x64（直链）：<a href="https://github.com/clash-verge-rev/clash-verge-rev/releases/download/v2.4.7/Clash.Verge_2.4.7_x64-setup.exe" target="_blank" rel="noreferrer">下载安装包</a></li><li>Windows ARM64（直链）：<a href="https://github.com/clash-verge-rev/clash-verge-rev/releases/download/v2.4.7/Clash.Verge_2.4.7_arm64-setup.exe" target="_blank" rel="noreferrer">下载安装包</a></li><li>Windows x64（镜像加速）：<a href="https://gh.xxooo.cf/https://github.com/clash-verge-rev/clash-verge-rev/releases/download/v2.4.7/Clash.Verge_2.4.7_x64-setup.exe" target="_blank" rel="noreferrer">下载安装包</a></li><li>当前参考版本：<code>v2.4.7</code></li></ul><p>安装说明：下载 <code>x64-setup.exe</code> 后正常安装并首次启动；如遇系统安全提示，选择继续运行。</p><h2 id="配置教程" tabindex="-1">配置教程 <a class="header-anchor" href="#配置教程" aria-label="Permalink to &quot;配置教程&quot;">​</a></h2><h3 id="步骤一-复制订阅链接" tabindex="-1">步骤一：复制订阅链接 <a class="header-anchor" href="#步骤一-复制订阅链接" aria-label="Permalink to &quot;步骤一：复制订阅链接&quot;">​</a></h3><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">自由港机场会员中心</a>，在「我的订阅」的订阅链接区域，点击右侧的<strong>复制</strong>按钮复制订阅链接；也可以直接点击 <strong>Clash Verge Rev</strong> 下方的<strong>一键导入</strong>尝试自动唤起软件。</p><p><img src="'+s+'" alt="在会员中心复制订阅链接或一键导入"></p><h3 id="步骤二-新建订阅" tabindex="-1">步骤二：新建订阅 <a class="header-anchor" href="#步骤二-新建订阅" aria-label="Permalink to &quot;步骤二：新建订阅&quot;">​</a></h3><p>打开 Clash Verge，点击左侧的<strong>订阅</strong>，再点击右上角的<strong>新建</strong>。</p><p><img src="'+l+'" alt="在订阅页点击新建"></p><h3 id="步骤三-填写配置信息" tabindex="-1">步骤三：填写配置信息 <a class="header-anchor" href="#步骤三-填写配置信息" aria-label="Permalink to &quot;步骤三：填写配置信息&quot;">​</a></h3><p>在弹出的「新建配置」窗口中：</p><ol><li><strong>类型</strong>：保持 <code>Remote</code></li><li><strong>名称</strong>：填写便于识别的名称，例如 <code>FreedomPort</code></li><li><strong>订阅链接</strong>：粘贴步骤一复制的订阅链接</li><li><strong>更新间隔</strong>：填入 <code>1440</code>（分钟，即每 24 小时自动更新一次）</li><li>向下滑动并开启<strong>允许自动更新</strong>，最后点击<strong>保存</strong></li></ol><p><img src="'+n+'" alt="填写名称、订阅链接、更新间隔并保存"></p><h3 id="步骤四-开启系统代理" tabindex="-1">步骤四：开启系统代理 <a class="header-anchor" href="#步骤四-开启系统代理" aria-label="Permalink to &quot;步骤四：开启系统代理&quot;">​</a></h3><p>进入左侧的<strong>设置</strong>页，打开<strong>系统代理</strong>开关即可开始代理上网。</p><p>如果遇到 Telegram 等应用无法登录，请同时打开<strong>虚拟网卡模式（TUN）</strong>。</p><p><img src="'+d+'" alt="在设置页开启系统代理"></p><h3 id="步骤五-选择模式与节点" tabindex="-1">步骤五：选择模式与节点 <a class="header-anchor" href="#步骤五-选择模式与节点" aria-label="Permalink to &quot;步骤五：选择模式与节点&quot;">​</a></h3><p>进入左侧的<strong>代理</strong>页：</p><ul><li>正常情况使用<strong>规则</strong>模式，国内直连、国外走代理，可节省流量</li><li>如果在意 DNS 泄露，切换到<strong>全局</strong>模式</li><li>在节点列表中选择一个延迟较低的节点或策略组</li></ul><p><img src="'+h+'" alt="在代理页选择模式与节点"></p><p>选择完成后，打开浏览器访问外网验证是否连接正常。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><ul><li><strong>策略分流</strong>：支持规则、全局、直连模式，支持策略组自动 / 手动切换</li><li><strong>状态与日志</strong>：可查看连接情况与规则命中，快速定位连接失败原因</li><li><strong>可视化管理</strong>：图形界面直观操作配置，适合非命令行用户日常维护</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 导入成功但没有节点？</strong> A: 先在订阅页手动更新配置；若仍为空，检查订阅链接是否可访问，确认账号套餐有效、流量未用完。</p><p><strong>Q: 节点都超时？</strong> A: 切换网络重试；更换低延迟节点；确认本地防火墙未拦截应用。</p><p><strong>Q: 连接后无法打开网页？</strong> A: 检查模式是否为规则 / 全局，确认系统代理已启用后再测试。</p><p><strong>Q: 检测到 DNS 泄露？</strong> A: 切换到全局模式，或参考<a href="./../../guide/privacy">代理后的隐私保护</a>。</p><p>更多问题见<a href="./../../guide/faq">常见问题 FAQ</a>。</p><hr><blockquote><p>最后更新：2026 年 3 月 28 日 · 适用版本 Clash Verge Rev v2.4.7</p></blockquote>',40)])])}const _=t(i,[["render",g]]);export{f as __pageData,_ as default};
